     8â†’/**
     9â†’ * Performs the fold-left (forward accumulation) algorithm using the given IAccumulator
    10â†’ * The general forward accumulation algorithm would not take an accumulator as a top-level
    11â†’ * input parameter, instead the accumulator would be hidden inside the algorithm.   
    12â†’ * But since the fold process, makes the folding process invariant and the accumulator the
    13â†’ * variant piece, the accumulator is thus necessarily an input parameter here.
    14â†’ * @author swong
    15â†’ *
    16â†’ */
    17â†’public class FoldLAlgo implements IListAlgo {
    18â†’
    19â†’	@Override
    20â†’	public Object emptyCase(MTList host, Object... accs) {
    21â†’		return accs[0];
    22â†’	}
    23â†’
    24â†’	@Override
    25â†’	public Object nonEmptyCase(NEList host, Object... accs) {
    26â†’		// Typically, the base case value of the accumulator is passed to the 
    27â†’		// helper here and the input parameter above is ignored. 
    28â†’		// But since the IAccumulator is constructed already holding its 
    29â†’		// base case value and given as the above input parameter, we 
    30â†’		// simply do the first accumulation and then pass it along. 
    31â†’		((IAccumulator) accs[0]).accumulate(host.getFirst());
    32â†’		return host.getRest().execute(helper, accs[0]);
    33â†’	}
    34â†’
    35â†’	/**
    36â†’	 * Helper visitor 
    37â†’	 * Arguable, this visitor above is unnecessary, but idea here was 
    38â†’	 * to stick to the general architecture of any forward accumulation 
    39â†’	 * algorithm, which foldl represents.
    40â†’	 */
    41â†’	private IListAlgo helper = new IListAlgo() {
    42â†’
    43â†’		@Override
    44â†’		public Object emptyCase(MTList host, Object... accs) {
    45â†’			return accs[0];
    46â†’		}
    47â†’
    48â†’		@Override
    49â†’		public Object nonEmptyCase(NEList host, Object... accs) {
    50â†’			// Process the incoming accumulator
    51â†’			((IAccumulator) accs[0]).accumulate(host.getFirst());
    52â†’			// Pass the processed accumulator along.
    53â†’			return host.getRest().execute(this, accs); // Tail-call -- can be optimized into a fast loop!
    54â†’		}
    55â†’
    56â†’	};
