public class FromNthAlgo implements IListAlgo {
	/**
	 * Returns zero always.
	 */
	public Object emptyCase(MTList host, Object... nu) {
		return 0;
	}

	/**
	 * Decrement the counter; once it drops below 0, add host.getFirst() to the sum.
	 * params[0] is the counter N as a String.
	 */
	public Object nonEmptyCase(NEList host, Object... params) {
		int n = Integer.parseInt((String) params[0]);
		int remaining = n - 1;
		int current = remaining < 0 ? (int) host.getFirst() : 0;
		return current + (int) host.getRest().execute(this, String.valueOf(remaining));
	}

}

