public class RemoveSmallestRevAlgo implements IListAlgo {
	/**
	 * Returns an empty list (base case for the result list).
	 */
	public Object emptyCase(MTList host, Object... nu) {
		return MTList.Singleton;
	}

	/**
	 * Compares host.getFirst() against the minimum of the rest.
	 * If current is the minimum, skip it; otherwise prepend it to the processed rest.
	 */
	public Object nonEmptyCase(NEList host, Object... nu) {
		Object[] restResult = (Object[]) host.getRest().execute(helper, nu);
		IList restModified = (IList) restResult[0];
		int restMin = (int) restResult[1];

		int first = (int) host.getFirst();
		if (first <= restMin) {
			// first is the global minimum; skip it, return original unmodified rest
			return host.getRest();
		} else {
			// first is not the minimum; prepend it to the modified rest
			return new NEList(first, restModified);
		}
	}

	/**
	 * Helper that returns Object[]{modifiedList, minValue} flowing from right to left.
	 */
	private IListAlgo helper = new IListAlgo() {
		@Override
		public Object emptyCase(MTList host, Object... nu) {
			return new Object[]{MTList.Singleton, Integer.MAX_VALUE};
		}

		@Override
		public Object nonEmptyCase(NEList host, Object... nu) {
			Object[] restResult = (Object[]) host.getRest().execute(this, nu);
			IList restModified = (IList) restResult[0];
			int restMin = (int) restResult[1];

			int first = (int) host.getFirst();
			if (first <= restMin) {
				// first is the minimum in this sublist; skip it, return original rest
				return new Object[]{host.getRest(), first};
			} else {
				// first is not minimum; keep it prepended to modified rest
				return new Object[]{new NEList(first, restModified), restMin};
			}
		}
	};

}

