/**
 * Returns true if the target is found in this element or the rest.
 */
public Object nonEmptyCase(NEList host, Object... param) {
	boolean restResult = (Boolean) host.getRest().execute(this, param);
	int target = Integer.parseInt((String) param[0]);
	return restResult || (target == (int) host.getFirst());
}
